import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query"
import api from "./api"
import { getToken } from "@/utils/auth"

export interface Appointment {
    id: number;
    dentist_id: number;
    patient_id: number;
    start_time: string;
    end_time: string;
    status: "pending" | "confirmed" | "moved" | "cancelled" | "completed";
    service?: string | null;
    price?: number | null;
    notes?: string | null;
    cancel_reason?: string | null;
    dentist_name?: string;
    patient_name?: string;
    visit_type?: "primary" | "follow_up";
}

export interface AppointmentCreate {
    dentist_id: number;
    patient_id?: number;
    start_time: string;
    end_time: string;
    service?: string;
    price?: number;
    notes?: string;
    visit_type?: "primary" | "follow_up";
}

const getAnyToken = (): string | null => {
    if (typeof window === 'undefined') return null;
    return sessionStorage.getItem('access_token') || localStorage.getItem('access_token');
};

export const useCreateAppointment = () => {
    const queryClient = useQueryClient();
    return useMutation({
        mutationFn: async (data: AppointmentCreate) => {
            const accessToken = getAnyToken();
            const isLocalMode = accessToken?.startsWith('local_token_');

            if (isLocalMode) {
                const raw = JSON.parse(localStorage.getItem('appointments') || '[]');
                const patients = JSON.parse(localStorage.getItem('patients') || '[]');
                const patient = patients.find((p: any) => p.id === data.patient_id);
                const start = new Date(data.start_time);

                const newApt = {
                    ...data,
                    id: Math.max(0, ...raw.map((a: any) => a.id)) + 1,
                    status: 'pending',
                    created_at: new Date().toISOString(),
                    patient_name: patient ? patient.full_name : 'Пациент',
                    doctor_name: 'Доктор',
                    date: start.toLocaleDateString('ru-RU'),
                    time: start.toLocaleTimeString('ru-RU', { hour: '2-digit', minute: '2-digit' }),
                };
                raw.push(newApt);
                localStorage.setItem('appointments', JSON.stringify(raw));

                return {
                    id: newApt.id,
                    dentist_id: newApt.dentist_id,
                    patient_id: newApt.patient_id || 1,
                    start_time: newApt.start_time,
                    end_time: newApt.end_time,
                    status: 'pending',
                    service: newApt.service,
                    price: newApt.price,
                    notes: newApt.notes,
                    patient_name: newApt.patient_name,
                    dentist_name: newApt.doctor_name
                } as Appointment;
            }

            const response = await api.post<Appointment>('/appointments/', data);
            return response.data;
        },
        onSuccess: (_data, variables) => {
            queryClient.invalidateQueries({ queryKey: ['appointments'] });
            queryClient.invalidateQueries({ queryKey: ['myAppointments'] });
            queryClient.invalidateQueries({ queryKey: ['patients'] });
            if (variables.patient_id) {
                queryClient.invalidateQueries({ queryKey: ['patientAppointments', variables.patient_id] });
            }
        }
    });
};

export const useMyAppointments = () => {
    const useApi = process.env.NEXT_PUBLIC_USE_API !== 'false';

    return useQuery({
        queryKey: ['myAppointments'],
        queryFn: async (): Promise<Appointment[]> => {
            const accessToken = getAnyToken();
            const isLocalMode = accessToken?.startsWith('local_token_');

            if (isLocalMode || !useApi) {
                const raw = JSON.parse(localStorage.getItem('appointments') || '[]');
                const userData = JSON.parse(sessionStorage.getItem('user_data') || localStorage.getItem('user_data') || '{}');

                return raw.map((a: any) => {
                    let start_time = a.start_time || a.created_at || new Date().toISOString();
                    if (a.date && a.time) {
                        const parts = a.date.split('.');
                        if (parts.length === 3) {
                            start_time = `${parts[2]}-${parts[1]}-${parts[0]}T${a.time}:00`;
                        }
                    }
                    const end_time = a.end_time || new Date(new Date(start_time).getTime() + 60 * 60 * 1000).toISOString();
                    return {
                        id: a.id,
                        dentist_id: a.doctor_id || a.dentist_id || 2,
                        patient_id: a.patient_id || 1,
                        start_time,
                        end_time,
                        status: (a.status === 'upcoming' ? 'pending' : a.status === 'past' ? 'completed' : a.status) as Appointment['status'],
                        service: a.service || null,
                        price: a.price || null,
                        notes: a.notes || a.comment || null,
                        dentist_name: a.doctor_name || a.dentist_name || 'Доктор',
                        patient_name: a.patient_name || userData.full_name || 'Пациент',
                    };
                });
            }

            try {
                const response = await api.get<Appointment[]>('/appointments/me');
                return response.data;
            } catch (err: any) {
                if (err.response?.status === 401) return [];
                throw err;
            }
        },
        enabled: !!getAnyToken(),
        staleTime: 0,
        refetchOnMount: 'always',
        refetchOnWindowFocus: true,
    });
};

export const useUpdateAppointment = () => {
    const queryClient = useQueryClient();
    return useMutation({
        mutationFn: async ({ id, ...data }: { id: number } & Partial<Appointment>) => {
            const accessToken = getAnyToken();
            const isLocalMode = accessToken?.startsWith('local_token_');

            if (isLocalMode) {
                const raw = JSON.parse(localStorage.getItem('appointments') || '[]');
                const updated = raw.map((a: any) => {
                    if (a.id === id) {
                        return { ...a, ...data };
                    }
                    return a;
                });
                localStorage.setItem('appointments', JSON.stringify(updated));
                return { id, ...data } as Appointment;
            }

            const response = await api.patch<Appointment>(`/appointments/${id}`, data);
            return response.data;
        },
        onSuccess: (data) => {
            queryClient.invalidateQueries({ queryKey: ['appointments'] });
            queryClient.invalidateQueries({ queryKey: ['myAppointments'] });
            queryClient.invalidateQueries({ queryKey: ['patients'] });
            if (data?.patient_id) {
                queryClient.invalidateQueries({ queryKey: ['patientAppointments', data.patient_id] });
            }
        }
    });
};

export const useCancelAppointment = () => {
    const queryClient = useQueryClient();
    return useMutation({
        mutationFn: async ({ id, reason }: { id: number; reason?: string }) => {
            const response = await api.patch<Appointment>(`/appointments/${id}`, {
                status: 'cancelled',
                cancel_reason: reason
            });
            return response.data;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['appointments'] });
            queryClient.invalidateQueries({ queryKey: ['myAppointments'] });
            queryClient.invalidateQueries({ queryKey: ['patients'] });
        }
    });
};

export const useRescheduleAppointment = () => {
    const queryClient = useQueryClient();
    return useMutation({
        mutationFn: async ({ id, start_time, end_time }: { id: number; start_time: string; end_time: string }) => {
            const response = await api.patch<Appointment>(`/appointments/${id}`, {
                start_time,
                end_time,
                status: 'moved'
            });
            return response.data;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['appointments'] });
            queryClient.invalidateQueries({ queryKey: ['myAppointments'] });
            queryClient.invalidateQueries({ queryKey: ['patients'] });
        }
    });
};

export const getPatientAppointments = async (patientId: number): Promise<Appointment[]> => {
    const response = await api.get<Appointment[]>(`/appointments/patient/${patientId}`);
    return response.data;
};

export const usePatientAppointments = (patientId: number) => {
    return useQuery({
        queryKey: ['patientAppointments', patientId],
        queryFn: () => getPatientAppointments(patientId),
        enabled: !!patientId,
        staleTime: 0,
        refetchOnMount: 'always',
    });
};

export const useAppointment = (id: number) => {
    return useQuery({
        queryKey: ['appointment', id],
        queryFn: async () => {
            const response = await api.get<Appointment>(`/appointments/${id}`);
            return response.data;
        },
        enabled: !!id,
    });
};

import { useQuery } from "@tanstack/react-query";
import api from "./api";
import { getToken } from "@/utils/auth";

export interface MedcardAllergy {
  id: number;
  allergen_name: string;
  reaction_type: string | null;
  severity: string | null;
  notes: string | null;
  documented_at: string | null;
}

export interface MedcardPrescription {
  id: number;
  medication_name: string;
  dosage: string | null;
  frequency: string | null;
  duration: string | null;
  notes: string | null;
  prescribed_at: string | null;
}

export interface MedcardAppointment {
  id: number;
  start_time: string;
  end_time: string;
  service: string | null;
  status: "pending" | "confirmed" | "moved" | "cancelled" | "completed";
  visit_type: string | null;
  notes: string | null;
  diagnosis: string | null;
  treatment_notes: string | null;
  dentist_name: string | null;
}

export interface MedcardPatient {
  id: number;
  full_name: string;
  birth_date: string | null;
  gender: string | null;
  address: string | null;
  phone: string | null;
}

export interface MedcardData {
  patient: MedcardPatient;
  allergies: MedcardAllergy[];
  prescriptions: MedcardPrescription[];
  appointments: MedcardAppointment[];
}

const safeParse = <T,>(value: string | null, fallback: T): T => {
  if (!value) return fallback;
  try {
    return JSON.parse(value) as T;
  } catch {
    return fallback;
  }
};

const emptyMedcard = (): MedcardData => ({
  patient: {
    id: 1,
    full_name: "Patient",
    birth_date: null,
    gender: null,
    address: null,
    phone: null,
  },
  allergies: [],
  prescriptions: [],
  appointments: [],
});

const buildLocalMedcard = (): MedcardData => {
  if (typeof window === 'undefined') return emptyMedcard();

  const userData = safeParse<Record<string, any>>(localStorage.getItem("user_data"), {});
  const patientProfile = safeParse<Record<string, any>>(localStorage.getItem("patient_profile"), {});
  const rawAppointments = safeParse<any[]>(localStorage.getItem("appointments"), []);

  const appointments: MedcardAppointment[] = rawAppointments.map((item: any) => {
    let startTime = item.start_time || item.created_at || new Date().toISOString();

    if (item.date && item.time) {
      const parts = item.date.split(".");
      if (parts.length === 3) {
        startTime = `${parts[2]}-${parts[1]}-${parts[0]}T${item.time}:00`;
      }
    }

    const endTime =
      item.end_time || new Date(new Date(startTime).getTime() + 60 * 60 * 1000).toISOString();

    return {
      id: item.id,
      start_time: startTime,
      end_time: endTime,
      service: item.service || item.title || null,
      status: (item.status === "upcoming" ? "pending" : item.status === "past" ? "completed" : item.status) || "pending",
      visit_type: item.visit_type || "primary",
      notes: item.notes || item.comment || null,
      diagnosis: item.diagnosis || null,
      treatment_notes: item.treatment_notes || null,
      dentist_name: item.dentist_name || item.doctor_name || "Shifokor",
    };
  });

  const medcard = emptyMedcard();

  return {
    ...medcard,
    patient: {
      id: Number(userData.patient_id || patientProfile.id || 1),
      full_name: patientProfile.name || userData.full_name || "Patient",
      birth_date: patientProfile.birthYear ? `${patientProfile.birthYear}-01-01` : null,
      gender:
        patientProfile.gender === "Мужчина" ? "male" :
        patientProfile.gender === "Женщина" ? "female" :
        userData.gender || null,
      address: patientProfile.address || null,
      phone: userData.phone || null,
    },
    allergies: [],
    prescriptions: [],
    appointments,
  };
};

export const usePatientMedcard = (patientId: number) => {
  return useQuery({
    queryKey: ["medcard", patientId],
    queryFn: async (): Promise<MedcardData> => {
      const res = await api.get<MedcardData>(`/patients/${patientId}/medcard`);
      return res.data;
    },
    enabled: !!patientId,
    staleTime: 30_000,
  });
};

export const useMyMedcard = () => {
  return useQuery({
    queryKey: ["myMedcard"],
    queryFn: async (): Promise<MedcardData> => {
      const accessToken = getToken() || (typeof window !== 'undefined' ? sessionStorage.getItem("access_token") : null);
      const isLocalMode = accessToken?.startsWith("local_token_");

      if (isLocalMode) {
        return buildLocalMedcard();
      }

      try {
        const res = await api.get<MedcardData>("/patients/me/medcard");
        return res.data;
      } catch {
        return buildLocalMedcard();
      }
    },
    staleTime: 30_000,
  });
};

import { useQuery } from '@tanstack/react-query';
import api from './api';

export interface Notification {
  id: number;
  user_id: number;
  type: string;
  title: string;
  message: string;
  is_read: boolean;
  created_at: string;
}

export const useNotifications = () => {
    return useQuery({
        queryKey: ['notifications'],
        queryFn: async (): Promise<Notification[]> => {
            const response = await api.get('/api/notifications/');
            return response.data;
        }
    });
};

export const useUnreadCount = () => {
    return useQuery({
        queryKey: ['notifications', 'unread-count'],
        queryFn: async (): Promise<number> => {
            try {
                const response = await api.get('/api/notifications/unread-count');
                return response.data.unread_count || 0;
            } catch (err) {
                return 0;
            }
        },
        refetchInterval: 30000,
    });
};

export const markAsRead = async (id: number): Promise<void> => {
  await api.patch(`/api/notifications/${id}/read`);
};

export const markAllAsRead = async (): Promise<void> => {
  await api.patch('/api/notifications/mark-all-read');
};

export const deleteAllNotifications = async (): Promise<void> => {
  await api.delete('/api/notifications/delete-all');
};

export const getUnreadCount = async (): Promise<number> => {
    try {
        const response = await api.get('/api/notifications/unread-count');
        return response.data.unread_count || 0;
    } catch (err) {
        return 0;
    }
};

export const getNotifications = async (): Promise<Notification[]> => {
  const response = await api.get('/api/notifications/');
  return response.data;
};

import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query"
import api from "./api"
import { isPatient, isDentist, isAuthenticated, getUserRole, getToken } from "@/utils/auth"

export interface Patient {
    id: number;
    user_id: number;
    full_name: string;
    birth_date?: string | null;
    gender?: string | null;
    address?: string | null;
    phone?: string | null;
    source?: string | null;
    status?: string | null;
    dentist_id?: number | null;
}

export interface DentistProfile {
    id: number;
    user_id: number;
    full_name: string;
    pinfl: string | null;
    diploma_number: string | null;
    verification_status: "pending" | "approved" | "rejected";
    specialization?: string;
    education?: string;
    phone?: string;
    email?: string;
    address?: string;
    clinic?: string;
    birth_date?: string | null;
    schedule?: string;
    work_hours?: string;
    telegram?: string;
    instagram?: string;
    whatsapp?: string;
    latitude?: number | null;
    longitude?: number | null;
    experience_years?: number | null;
    rating?: number | null;
    review_count?: number | null;
    works_photos?: string;
    diploma_photo_url?: string;
    age?: number | null;
    gender?: string | null;
}

export const usePatientProfile = () => {
    const accessToken = getToken()
    const userRole = getUserRole()

    return useQuery({
        queryKey: ['patientProfile'],
        queryFn: async () => {
            const response = await api.get<Patient>('/patients/me');
            return response.data;
        },
        enabled: !!accessToken && isAuthenticated() && isPatient() && userRole === 'patient',
    })
}

export const useDentistProfile = () => {
    const accessToken = getToken()
    const userRole = getUserRole()

    return useQuery({
        queryKey: ['dentistProfile'],
        queryFn: async () => {
            const response = await api.get<DentistProfile>('/dentists/me');
            return response.data;
        },
        enabled: !!accessToken && isAuthenticated() && isDentist() && userRole === 'dentist',
        staleTime: 0,
        refetchOnMount: 'always',
    })
}

export const useAllPatients = () => {
    const accessToken = getToken()
    const userRole = getUserRole()

    return useQuery({
        queryKey: ['patients'],
        queryFn: async (): Promise<Patient[]> => {
            const isLocalMode = accessToken?.startsWith('local_token_');

            if (isLocalMode) {
                const patients = JSON.parse(localStorage.getItem('patients') || '[]');
                return patients;
            }

            const response = await api.get<Patient[]>('/patients/');
            return response.data;
        },
        enabled: !!accessToken && isAuthenticated() && isDentist() && userRole === 'dentist',
    });
}

export const useAllDentists = (params?: {
    search?: string;
    gender?: string;
    region?: string;
    district?: string;
    specialty?: string;
}) => {
    return useQuery({
        queryKey: ['dentists', params],
        queryFn: async () => {
            const response = await api.get<DentistProfile[]>('/dentists/', { params });
            return response.data;
        },
        retry: false,
        staleTime: 5 * 60 * 1000,
    });
}

export const usePatient = (id: number) => {
    return useQuery({
        queryKey: ['patient', id],
        queryFn: async () => {
            const response = await api.get<Patient>(`/patients/${id}`);
            return response.data;
        },
        enabled: !!id
    });
}

export const useCreatePatient = () => {
    const queryClient = useQueryClient();
    return useMutation({
        mutationFn: async (data: Omit<Patient, 'id' | 'user_id'> & { source?: string }) => {
            const accessToken = getToken() || (typeof window !== 'undefined' ? sessionStorage.getItem('access_token') : null);
            const isLocalMode = accessToken?.startsWith('local_token_');

            if (isLocalMode) {
                const raw = JSON.parse(localStorage.getItem('patients') || '[]');
                const userData = JSON.parse(localStorage.getItem('user_data') || '{}');
                const dentistId = userData.dentist_id || 1;

                const newPatient = {
                    ...data,
                    id: Math.max(0, ...raw.map((p: any) => p.id)) + 1,
                    user_id: 0,
                    dentist_id: dentistId,
                    created_at: new Date().toISOString()
                };
                raw.push(newPatient);
                localStorage.setItem('patients', JSON.stringify(raw));
                return newPatient as Patient;
            }

            const response = await api.post<Patient>('/patients/', data);
            return response.data;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['patients'] });
        }
    });
};

export interface MagicLink {
    token: string;
    expires_at: string;
    patient_id: number;
}

// Doktor bemor uchun magic-havola tokenini oladi (faqat dentist).
// To'liq URL'ni chaqiruvchi komponent quradi (origin + locale).
export const useGetMagicLink = () => {
    return useMutation({
        mutationFn: async (patientId: number): Promise<MagicLink> => {
            const response = await api.get<MagicLink>(`/patients/${patientId}/magic-link`);
            return response.data;
        },
    });
};

export const useUpdatePatient = () => {
    const queryClient = useQueryClient();
    return useMutation({
        mutationFn: async ({ id, ...data }: { id: number } & Partial<Omit<Patient, 'id' | 'user_id'>>) => {
            const response = await api.patch<Patient>(`/patients/${id}`, data);
            return response.data;
        },
        onSuccess: (_, variables) => {
            queryClient.invalidateQueries({ queryKey: ['patients'] });
            queryClient.invalidateQueries({ queryKey: ['patient', variables.id] });
        }
    });
};

export const useDeletePatient = () => {
    const queryClient = useQueryClient();
    return useMutation({
        mutationFn: async (id: number) => {
            const response = await api.delete<{ message: string }>(`/patients/${id}`);
            return response.data;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['patients'] });
        }
    });
};

export const useUpdateDentistProfile = () => {
    const queryClient = useQueryClient();
    return useMutation({
        mutationFn: async (data: Partial<{
            specialization: string;
            education: string;
            phone: string;
            address: string;
            clinic: string;
            birth_date: string | null;
            schedule: string;
            work_hours: string;
            telegram: string;
            instagram: string;
            whatsapp: string;
            latitude: number;
            longitude: number;
            works_photos: string;
            experience_years: number | null;
            age: number | null;
            gender: string | null;
        }>) => {
            const response = await api.put<DentistProfile>('/dentists/me', data);
            return response.data;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['dentistProfile'] });
        }
    });
};

export const useUploadDiploma = () => {
    const queryClient = useQueryClient();
    return useMutation({
        mutationFn: async (file: File) => {
            const formData = new FormData();
            formData.append('file', file);

            const response = await api.post('/dentists/me/diploma', formData, {
                headers: {
                    'Content-Type': 'multipart/form-data',
                },
            });
            return response.data;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['dentistProfile'] });
        }
    });
};

export interface DentistStats {
    total_patients: number;
    total_appointments: number;
    completed_appointments: number;
    pending_appointments: number;
    appointments_today: number;
    appointments_this_month: number;
    new_patients_this_week: number;
    average_rating: number;
    total_reviews: number;
}

export const useDentistStats = () => {
    const accessToken = getToken()
    const userRole = getUserRole()

    return useQuery({
        queryKey: ['dentistStats'],
        queryFn: async () => {
            const response = await api.get<DentistStats>('/dentists/me/stats');
            return response.data;
        },
        enabled: !!accessToken && isAuthenticated() && isDentist() && userRole === 'dentist',
    })
};

export const useSpecializationCounts = () => {
    return useQuery({
        queryKey: ['specializationCounts'],
        queryFn: async () => {
            const response = await api.get<Record<string, number>>('/dentists/specialization-counts');
            return response.data;
        },
        staleTime: 5 * 60 * 1000,
    });
};

