                                            <div className="flex items-center gap-1.5 text-gray-500 bg-gray-50 px-3 py-1 rounded-full text-xs font-bold">
                                                <User size={14} className="text-blue-500" />
                                                <span>{service.dentist_name || "Shifokor"}</span>
