/**
 * Database functions for Telegram bot language management
 * These functions interact with the Neon PostgreSQL database to store and retrieve user language preferences
 */

import { Pool } from 'pg';

// Database connection configuration
const getDatabaseUrl = (): string => {
  const databaseUrl = process.env.DATABASE_URL;
  if (!databaseUrl) {
    throw new Error('DATABASE_URL environment variable is not set');
  }
  return databaseUrl;
};

// Create a connection pool for better performance
let pool: Pool | null = null;

const getPool = (): Pool => {
  if (!pool) {
    pool = new Pool({
      connectionString: getDatabaseUrl(),
      ssl: {
        rejectUnauthorized: false
      },
      // Connection pool settings for Neon
      max: 10,
      idleTimeoutMillis: 30000,
      connectionTimeoutMillis: 2000,
    });
  }
  return pool;
};

/**
 * Save user language preference to database
 * @param chatId - Telegram chat ID (as string)
 * @param lang - Language code ('uz' or 'ru')
 * @returns Promise<void>
 */
export async function saveUserLang(chatId: string, lang: 'uz' | 'ru'): Promise<void> {
  if (!chatId) {
    throw new Error('ChatId is required');
  }
  
  if (lang !== 'uz' && lang !== 'ru') {
    throw new Error('Language must be either "uz" or "ru"');
  }

  const pool = getPool();
  const client = await pool.connect();
  
  try {
    // First, try to find user by telegram_id
    const findUserQuery = 'SELECT id FROM users WHERE telegram_id = $1';
    const findResult = await client.query(findUserQuery, [chatId]);
    
    if (findResult.rows.length > 0) {
      // User exists, update their language
      const updateQuery = 'UPDATE users SET language = $1 WHERE telegram_id = $2';
      await client.query(updateQuery, [lang, chatId]);
    } else {
      // User doesn't exist, create a new user record with minimal data
      // Note: This creates a user with telegram_id only, other fields will need to be filled later
      const insertQuery = `
        INSERT INTO users (telegram_id, language, phone, role, is_active) 
        VALUES ($1, $2, $3, $4, $5)
        ON CONFLICT (telegram_id) 
        DO UPDATE SET language = EXCLUDED.language
      `;
      // Use a placeholder phone number that will be updated when user completes registration
      const placeholderPhone = `telegram_${chatId}`;
      await client.query(insertQuery, [chatId, lang, placeholderPhone, 'PATIENT', true]);
    }
  } catch (error) {
    console.error('Error saving user language:', error);
    throw new Error(`Failed to save user language: ${error instanceof Error ? error.message : 'Unknown error'}`);
  } finally {
    client.release();
  }
}

/**
 * Get user language preference from database
 * @param chatId - Telegram chat ID (as string)
 * @returns Promise<'uz' | 'ru'> - Returns 'uz' as default if user not found or language not set
 */
export async function getUserLang(chatId: string): Promise<'uz' | 'ru'> {
  if (!chatId) {
    console.warn('ChatId is empty, returning default language');
    return 'uz';
  }

  const pool = getPool();
  const client = await pool.connect();
  
  try {
    const query = 'SELECT language FROM users WHERE telegram_id = $1';
    const result = await client.query(query, [chatId]);
    
    if (result.rows.length > 0) {
      const language = result.rows[0].language;
      // Ensure we return a valid language, default to 'uz' if invalid
      return (language === 'ru' || language === 'uz') ? language : 'uz';
    }
    
    // User not found, return default language
    return 'uz';
  } catch (error) {
    console.error('Error getting user language:', error);
    // Return default language on error to ensure bot continues working
    return 'uz';
  } finally {
    client.release();
  }
}

/**
 * Check if user exists in database by telegram_id
 * @param chatId - Telegram chat ID (as string)
 * @returns Promise<boolean>
 */
export async function userExists(chatId: string): Promise<boolean> {
  if (!chatId) {
    return false;
  }

  const pool = getPool();
  const client = await pool.connect();
  
  try {
    const query = 'SELECT 1 FROM users WHERE telegram_id = $1 LIMIT 1';
    const result = await client.query(query, [chatId]);
    return result.rows.length > 0;
  } catch (error) {
    console.error('Error checking user existence:', error);
    return false;
  } finally {
    client.release();
  }
}

/**
 * Get user information by telegram_id
 * @param chatId - Telegram chat ID (as string)
 * @returns Promise<User | null>
 */
export async function getUserByTelegramId(chatId: string): Promise<any | null> {
  if (!chatId) {
    return null;
  }

  const pool = getPool();
  const client = await pool.connect();
  
  try {
    const query = 'SELECT * FROM users WHERE telegram_id = $1';
    const result = await client.query(query, [chatId]);
    
    if (result.rows.length > 0) {
      return result.rows[0];
    }
    
    return null;
  } catch (error) {
    console.error('Error getting user by telegram_id:', error);
    return null;
  } finally {
    client.release();
  }
}

/**
 * Close the database connection pool
 * Should be called when the application shuts down
 */
export async function closeDatabasePool(): Promise<void> {
  if (pool) {
    await pool.end();
    pool = null;
  }
}

/**
 * Telegram Mini App language detection utilities
 * Detects user language from Telegram WebApp data and integrates with next-intl
 */

import { normalizeLanguage, isLanguageSupported, type SupportedLanguage } from '@/locales/i18n';

/**
 * Detect language from Telegram WebApp data
 * @returns Detected language code ('uz' or 'ru') with fallback to 'uz'
 */
export function detectTelegramLanguage(): SupportedLanguage {
  try {
    // Check if we're in a Telegram WebApp environment
    if (typeof window === 'undefined' || !window.Telegram?.WebApp) {
      console.log('Not in Telegram WebApp environment, using default language');
      return 'uz';
    }

    const webApp = window.Telegram.WebApp;
    const user = webApp.initDataUnsafe?.user;
    
    if (!user) {
      console.log('No Telegram user data available, using default language');
      return 'uz';
    }

    const telegramLangCode = user.language_code;
    console.log('Detected Telegram language code:', telegramLangCode);

    // Map Telegram language codes to our supported languages
    if (telegramLangCode) {
      // Handle Russian language codes
      if (telegramLangCode === 'ru' || telegramLangCode.startsWith('ru-')) {
        return 'ru';
      }
      
      // Handle Uzbek language codes
      if (telegramLangCode === 'uz' || telegramLangCode.startsWith('uz-')) {
        return 'uz';
      }
      
      // For other languages, check if we support them directly
      if (isLanguageSupported(telegramLangCode)) {
        return telegramLangCode;
      }
    }

    // Default to Uzbek for unsupported languages
    console.log('Unsupported or missing language code, defaulting to Uzbek');
    return 'uz';
  } catch (error) {
    console.error('Error detecting Telegram language:', error);
    return 'uz';
  }
}

/**
 * Get Telegram user information
 * @returns Telegram user data or null if not available
 */
export function getTelegramUser() {
  try {
    if (typeof window === 'undefined' || !window.Telegram?.WebApp) {
      return null;
    }

    return window.Telegram.WebApp.initDataUnsafe?.user || null;
  } catch (error) {
    console.error('Error getting Telegram user:', error);
    return null;
  }
}

/**
 * Get Telegram chat information
 * @returns Telegram chat data or null if not available
 */
export function getTelegramChat() {
  try {
    if (typeof window === 'undefined' || !window.Telegram?.WebApp) {
      return null;
    }

    return window.Telegram.WebApp.initDataUnsafe?.chat || null;
  } catch (error) {
    console.error('Error getting Telegram chat:', error);
    return null;
  }
}

/**
 * Check if the app is running in Telegram WebApp environment
 * @returns True if running in Telegram WebApp
 */
export function isTelegramWebApp(): boolean {
  try {
    return typeof window !== 'undefined' && !!window.Telegram?.WebApp;
  } catch (error) {
    return false;
  }
}

/**
 * Initialize Telegram WebApp and return detected language
 * Should be called when the app loads
 * @returns Promise<SupportedLanguage> - Detected language
 */
export function initializeTelegramWebApp(): Promise<SupportedLanguage> {
  return new Promise((resolve) => {
    try {
      if (!isTelegramWebApp()) {
        console.log('Not in Telegram WebApp, using default language');
        resolve('uz');
        return;
      }

      const webApp = window.Telegram!.WebApp!;
      
      // Initialize the WebApp
      if (webApp.ready) {
        webApp.ready();
      }
      
      // Expand the WebApp to full height
      if (webApp.expand) {
        webApp.expand();
      }

      // Detect language
      const detectedLanguage = detectTelegramLanguage();
      
      console.log('Telegram WebApp initialized with language:', detectedLanguage);
      resolve(detectedLanguage);
    } catch (error) {
      console.error('Error initializing Telegram WebApp:', error);
      resolve('uz');
    }
  });
}

/**
 * Get the appropriate locale for next-intl based on Telegram language
 * Maps our supported languages to next-intl locale codes
 * @param telegramLang - Detected Telegram language
 * @returns Locale string for next-intl
 */
export function getTelegramLocale(telegramLang?: SupportedLanguage): string {
  const lang = telegramLang || detectTelegramLanguage();
  
  // Map to next-intl locale codes
  switch (lang) {
    case 'ru':
      return 'ru';
    case 'uz':
    default:
      return 'uz';
  }
}

/**
 * Hook for React components to get Telegram language
 * @returns Object with language detection utilities
 */
export function useTelegramLanguage() {
  const detectLanguage = () => detectTelegramLanguage();
  const getUser = () => getTelegramUser();
  const getChat = () => getTelegramChat();
  const isWebApp = () => isTelegramWebApp();
  
  return {
    detectLanguage,
    getUser,
    getChat,
    isWebApp,
    initializeWebApp: initializeTelegramWebApp,
    getTelegramLocale
  };
}

import { uzTranslations } from './uz';
import { ruTranslations } from './ru';
import type { BotTranslations } from './uz';

export type SupportedLanguage = 'uz' | 'ru';

const translations: Record<SupportedLanguage, BotTranslations> = {
  uz: uzTranslations,
  ru: ruTranslations
};

/**
 * Translation function that returns the correct translation for a given key and language
 * @param key - Dot-notation key path (e.g., 'welcome.greeting', 'commands.help')
 * @param lang - Language code ('uz' or 'ru')
 * @returns Translated string or fallback to Uzbek if key/language not found
 */
export function t(key: string, lang: SupportedLanguage = 'uz'): string {
  try {
    // Ensure language is supported, fallback to Uzbek
    const language = lang === 'ru' ? 'ru' : 'uz';
    const translation = translations[language];
    
    // Split key by dots and traverse the object
    const keys = key.split('.');
    let result: any = translation;
    
    for (const k of keys) {
      if (result && typeof result === 'object' && k in result) {
        result = result[k];
      } else {
        // Key not found, try fallback to Uzbek if we were using Russian
        if (language === 'ru') {
          result = translations.uz;
          for (const fallbackKey of keys) {
            if (result && typeof result === 'object' && fallbackKey in result) {
              result = result[fallbackKey];
            } else {
              return `[Missing translation: ${key}]`;
            }
          }
          return result;
        }
        return `[Missing translation: ${key}]`;
      }
    }
    
    return typeof result === 'string' ? result : `[Invalid translation: ${key}]`;
  } catch (error) {
    // Fallback to Uzbek on any error
    if (lang !== 'uz') {
      return t(key, 'uz');
    }
    return `[Translation error: ${key}]`;
  }
}

/**
 * Get all available translations for a specific language
 * @param lang - Language code ('uz' or 'ru')
 * @returns Complete translation object for the language
 */
export function getTranslations(lang: SupportedLanguage = 'uz'): BotTranslations {
  const language = lang === 'ru' ? 'ru' : 'uz';
  return translations[language];
}

/**
 * Check if a language is supported
 * @param lang - Language code to check
 * @returns True if language is supported
 */
export function isLanguageSupported(lang: string): lang is SupportedLanguage {
  return lang === 'uz' || lang === 'ru';
}

/**
 * Normalize language code to supported language or default to Uzbek
 * @param lang - Language code to normalize
 * @returns Normalized language code ('uz' or 'ru')
 */
export function normalizeLanguage(lang?: string): SupportedLanguage {
  if (!lang) return 'uz';
  return isLanguageSupported(lang) ? lang : 'uz';
}

// Deep-merges scripts/_add.json into each messages/<locale>.json.
// _add.json shape: { "ru": {nested}, "uz": {nested}, "en": {nested}, "kz": {nested} }
const fs = require('fs');
const path = require('path');

const add = JSON.parse(fs.readFileSync(path.join(__dirname, '_add.json'), 'utf8'));

function deepMerge(target, src) {
  for (const k of Object.keys(src)) {
    if (src[k] && typeof src[k] === 'object' && !Array.isArray(src[k])) {
      if (!target[k] || typeof target[k] !== 'object') target[k] = {};
      deepMerge(target[k], src[k]);
    } else {
      target[k] = src[k];
    }
  }
  return target;
}

for (const locale of Object.keys(add)) {
  const file = path.join(__dirname, '..', 'messages', `${locale}.json`);
  const cur = JSON.parse(fs.readFileSync(file, 'utf8'));
  deepMerge(cur, add[locale]);
  fs.writeFileSync(file, JSON.stringify(cur, null, 2) + '\n', 'utf8');
  console.log('merged ->', locale);
}

