import { createSlice } from '@reduxjs/toolkit';
import type { PayloadAction } from '@reduxjs/toolkit';
import type { UserRole } from '@/types';

interface UserState {
  user: Record<string, any> | null;
  isAuthenticated: boolean;
  role: UserRole | null;
}

const initialState: UserState = {
  user: null,
  isAuthenticated: false,
  role: null,
};

const userSlice = createSlice({
  name: 'user',
  initialState,
  reducers: {
    setUser: (state, action: PayloadAction<Record<string, any>>) => {
      state.user = action.payload;
      state.isAuthenticated = true;
      if (action.payload.role) {
        state.role = action.payload.role;
      }
    },
    clearUser: (state) => {
      state.user = null;
      state.isAuthenticated = false;
      state.role = null;
    },
    updateUser: (state, action: PayloadAction<Record<string, any>>) => {
      if (state.user) {
        state.user = { ...state.user, ...action.payload };
      }
    },
  },
});

export const { setUser, clearUser, updateUser } = userSlice.actions;
export default userSlice.reducer;

export type NotificationType =
  | 'appointment_reminder'
  | 'appointment_rescheduled'
  | 'appointment_cancelled'
  | 'analytics_check'
  | 'rating_decreased'
  | 'rating_increased'
  | 'appointment_rated'
  | 'review_left'
  | 'payment_reminder';

export interface NotificationMetadata {
  patient_name?: string;
  new_date?: string;
  reason?: string;
  rating?: number;
  review?: string;
  stars?: number;
  [key: string]: any;
}

export interface Notification {
  id: number;
  user_id: number;
  notification_type: NotificationType;
  title: string;
  message: string;
  metadata: NotificationMetadata;
  is_read: boolean;
  created_at: string;
}

export interface UnreadCount {
  count: number;
}

export const getToken = (): string | null => {
  if (typeof window === 'undefined') return null;
  return localStorage.getItem('access_token');
};

const isLocalToken = (token: string | null): boolean => {
  return !!token && token.startsWith('local_token_');
};

const parseJwtPayload = (token: string): Record<string, unknown> | null => {
  try {
    const payload = token.split('.')[1];
    if (!payload) return null;

    const base64 = payload.replace(/-/g, '+').replace(/_/g, '/');
    const padded = base64.padEnd(base64.length + ((4 - (base64.length % 4)) % 4), '=');
    const decoded = atob(padded);
    return JSON.parse(decoded);
  } catch {
    return null;
  }
};

export const getUser = (): any | null => {
  if (typeof window === 'undefined') return null;
  const userStr = localStorage.getItem('user_data');
  if (!userStr) return null;
  try {
    return JSON.parse(userStr);
  } catch {
    return null;
  }
};

export const isAuthenticated = (): boolean => {
  const token = getToken();
  return !!token && token !== 'null' && token !== 'undefined';
};

export const getUserRole = (): 'patient' | 'dentist' | null => {
  const token = getToken();
  const user = getUser();

  if (token && !isLocalToken(token)) {
    const role = parseJwtPayload(token)?.role;
    if (role === 'patient' || role === 'dentist') {
      if (user && user.role !== role && typeof window !== 'undefined') {
        localStorage.setItem('user_data', JSON.stringify({ ...user, role }));
      }
      return role;
    }
  }

  return user?.role || null;
};

export const isPatient = (): boolean => getUserRole() === 'patient';
export const isDentist = (): boolean => getUserRole() === 'dentist';

export const logout = (): void => {
  if (typeof window === 'undefined') return;
  localStorage.removeItem('access_token');
  localStorage.removeItem('user_data');
  window.location.href = '/login';
};
